-- ============================================
-- TABLE: chat_history
-- Export date: 2026-01-16T17:44:10.493Z
-- Total rows: 2619
-- ============================================

-- Drop existing table if exists
DROP TABLE IF EXISTS public.chat_history CASCADE;

-- ============================================
-- 1. CREATE TABLE
-- ============================================
CREATE TABLE public.chat_history (
    id uuid NOT NULL DEFAULT gen_random_uuid(),
    user_id uuid NOT NULL,
    created_at timestamp with time zone NOT NULL DEFAULT now(),
    chat_id uuid,
    role text NOT NULL,
    content text NOT NULL,
    image_url text,
    CONSTRAINT chat_history_pkey PRIMARY KEY (id)
);

-- ============================================
-- 2. FOREIGN KEYS
-- ============================================
-- Note: Foreign key to chats table exists but commented out
-- to allow flexible restoration order
-- ALTER TABLE public.chat_history
--     ADD CONSTRAINT chat_history_chat_id_fkey
--     FOREIGN KEY (chat_id) REFERENCES public.chats(id);

-- ============================================
-- 3. INDEXES
-- ============================================
CREATE INDEX idx_chat_history_user_id ON public.chat_history USING btree (user_id);
CREATE INDEX idx_chat_history_chat_id ON public.chat_history USING btree (chat_id);
CREATE INDEX idx_chat_history_created_at ON public.chat_history USING btree (created_at);

-- ============================================
-- 4. ROW LEVEL SECURITY
-- ============================================
ALTER TABLE public.chat_history ENABLE ROW LEVEL SECURITY;

-- ============================================
-- 5. POLICIES
-- ============================================
CREATE POLICY "Users can delete their chat messages"
    ON public.chat_history
    FOR DELETE
    USING (EXISTS (
        SELECT 1 FROM chats
        WHERE chats.id = chat_history.chat_id
        AND chats.user_id = auth.uid()
    ));

CREATE POLICY "Users can insert their chat messages"
    ON public.chat_history
    FOR INSERT
    WITH CHECK (EXISTS (
        SELECT 1 FROM chats
        WHERE chats.id = chat_history.chat_id
        AND chats.user_id = auth.uid()
    ));

CREATE POLICY "Users can view their chat messages"
    ON public.chat_history
    FOR SELECT
    USING (EXISTS (
        SELECT 1 FROM chats
        WHERE chats.id = chat_history.chat_id
        AND chats.user_id = auth.uid()
    ));

-- ============================================
-- 6. TRIGGERS
-- ============================================
-- No triggers on this table

-- ============================================
-- 7. DATA INSERT (batches of 2)
-- ============================================
