    ('de59fa30-53f7-4a61-b4dd-f8cbbcf4e1a6'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-23T22:12:41.123596+00:00'::timestamptz, NULL, 'assistant', 'C''est notre première session, donc je te propose un exercice découpé en petites étapes pour comprendre où tu en es. D''accord, on va prendre un exemple concret pour bien comprendre la résolution d''une équation du second degré. C''est une méthode très importante, alors concentre-toi bien ! 😊', NULL);

INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('cbd00f58-170f-4fcb-aff4-7e7a873a03b3'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-24T16:43:42.469865+00:00'::timestamptz, NULL, 'user', 'Donne-moi un exercice dur sur les limites de suite.', NULL),
    ('3214627f-ce15-4ea9-8f00-98e4cf6c69de'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-24T16:43:42.959405+00:00'::timestamptz, NULL, 'assistant', 'Bien sûr, voici un exercice qui demande un peu de réflexion :

**Exercice :**

Soit la suite $(u_n)$ définie par $u_0 = 1$ et $u_{n+1} = \sqrt{u_n + 2}$ pour tout $n \in \mathbb{N}$.

1.  Montrer que la suite $(u_n)$ est majorée par 2.
2.  Montrer que la suite $(u_n)$ est croissante.
3.  En déduire que la suite $(u_n)$ converge et déterminer sa limite.

Bon courage ! N''hésite pas si tu as des questions en cours de route.', NULL);

INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('9beb260a-11be-49be-bb67-0bd77fbda778'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T14:52:17.788335+00:00'::timestamptz, '257136a2-7a9e-4930-be63-fed23e64e1a0'::uuid, 'assistant', '{"difficulte":"moyen","indices":["Pour calculer les premiers termes, remplace simplement $n$ par la valeur correspondante.","Pour la limite d''une fonction rationnelle (quotient de polynômes), on peut se concentrer sur les termes de plus haut degré.","Pour factoriser, pense à mettre $n$ en facteur au numérateur et au dénominateur.","La limite de $\\frac{1}{n}$ est une limite de référence que tu dois connaître.","Utilise les propriétés des limites pour les sommes et les quotients."],"justification":"L''élève a indiqué avoir du mal avec les limites de suites. Cet exercice est découpé en micro-questions pour diagnostiquer précisément les difficultés et revoir la méthode de calcul des limites de suites rationnelles.","type":"exercice_genere","chapitre":"Limites de suites","enonce":{"questions":["Calcule les trois premiers termes de la suite : $U_0$, $U_1$, $U_2$.","Pour étudier la limite de la suite $(U_n)$ lorsque $n$ tend vers l''infini, quel est le terme de plus haut degré au numérateur et au dénominateur ?","En factorisant par le terme de plus haut degré au numérateur et au dénominateur, écris la suite $(U_n)$ sous une autre forme.","Détermine la limite de $\\frac{1}{n}$ lorsque $n$ tend vers l''infini.","En déduis la limite de la suite $(U_n)$ lorsque $n$ tend vers l''infini et justifie ta réponse."],"contexte":"Soit la suite $(U_n)$ définie pour tout entier naturel $n$ par $U_n = \\frac{2n + 3}{n + 1}$."},"solution_complete":"1. Calcul des premiers termes :\n$U_0 = \\frac{2(0) + 3}{0 + 1} = \\frac{3}{1} = 3$\n$U_1 = \\frac{2(1) + 3}{1 + 1} = \\frac{5}{2} = 2,5$\n$U_2 = \\frac{2(2) + 3}{2 + 1} = \\frac{7}{3} \\approx 2,33$\n\n2. Les termes de plus haut degré sont $2n$ au numérateur et $n$ au dénominateur.\n\n3. Factorisation :\n$U_n = \\frac{n(2 + \\frac{3}{n})}{n(1 + \\frac{1}{n})} = \\frac{2 + \\frac{3}{n}}{1 + \\frac{1}{n}}$\n\n4. Limite de $\\frac{1}{n}$ :\n$\\lim_{n \\to +\\infty} \\frac{1}{n} = 0$\n\n5. Déduction de la limite de $U_n$ :\nComme $\\lim_{n \\to +\\infty} \\frac{3}{n} = 0$ et $\\lim_{n \\to +\\infty} \\frac{1}{n} = 0$,\nalors $\\lim_{n \\to +\\infty} (2 + \\frac{3}{n}) = 2 + 0 = 2$\net $\\lim_{n \\to +\\infty} (1 + \\frac{1}{n}) = 1 + 0 = 1$\nPar conséquent, par quotient des limites :\n$\\lim_{n \\to +\\infty} U_n = \\frac{2}{1} = 2$","message_introduction":"Bonjour ! Puisque tu as du mal avec les limites de suites, je te propose un exercice découpé en petites étapes pour que nous puissions identifier ensemble où tu bloques et t''aider à maîtriser ce concept important. 😊","exercice_id":"9dccc543-ca46-4a32-b492-d3647ae76262"}', NULL),
    ('9352a50a-60c3-497a-946d-c6ee1e9ade38'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T14:52:48.172306+00:00'::timestamptz, '257136a2-7a9e-4930-be63-fed23e64e1a0'::uuid, 'user', 'la limite c''est 2', NULL);

INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('a53dc2a1-d400-45e3-86b3-a6cc84f58f70'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T14:52:53.89914+00:00'::timestamptz, '4c3f2689-b0e2-4f16-a682-59c94b7ff693'::uuid, 'assistant', '{"type":"exercice_genere","message_introduction":"Tu as bien identifié la limite, c''est super ! Pour nous assurer que tu maîtrises bien toutes les étapes, je te propose un nouvel exercice sur les limites. 😊","solution_complete":"1. Le terme de plus haut degré au numérateur est $n^2$.\n2. Le terme de plus haut degré au dénominateur est $2n^2$.\n3. Factorisation :\n$V_n = \\frac{n^2(1 - \\frac{4}{n} + \\frac{1}{n^2})}{n^2(2 + \\frac{1}{n} - \\frac{3}{n^2})} = \\frac{1 - \\frac{4}{n} + \\frac{1}{n^2}}{2 + \\frac{1}{n} - \\frac{3}{n^2}}$\n4. Limites des termes :\n$\\lim_{n \\to +\\infty} \\frac{4}{n} = 0$\n$\\lim_{n \\to +\\infty} \\frac{1}{n^2} = 0$\n$\\lim_{n \\to +\\infty} \\frac{3}{n^2} = 0$\n5. Déduction de la limite de $V_n$ :\n$\\lim_{n \\to +\\infty} (1 - \\frac{4}{n} + \\frac{1}{n^2}) = 1 - 0 + 0 = 1$\n$\\lim_{n \\to +\\infty} (2 + \\frac{1}{n} - \\frac{3}{n^2}) = 2 + 0 - 0 = 2$\nPar conséquent, par quotient des limites :\n$\\lim_{n \\to +\\infty} V_n = \\frac{1}{2}$","chapitre":"Limites de suites","justification":"L''élève a trouvé la limite du premier exercice. Il est important de vérifier sa compréhension de la méthode de factorisation et de simplification pour les limites de suites rationnelles avec un nouvel exemple. Le découpage en micro-questions permet de s''assurer qu''il maîtrise chaque étape.","difficulte":"moyen","enonce":{"questions":["Quel est le terme de plus haut degré au numérateur de $V_n$ ?","Quel est le terme de plus haut degré au dénominateur de $V_n$ ?","En factorisant par le terme de plus haut degré au numérateur et au dénominateur, écris la suite $(V_n)$ sous une forme simplifiée.","Détermine la limite de chaque terme de la forme simplifiée lorsque $n$ tend vers l''infini.","En déduis la limite de la suite $(V_n)$ lorsque $n$ tend vers l''infini et justifie ta réponse."],"contexte":"Soit la suite $(V_n)$ définie pour tout entier naturel $n$ par $V_n = \\frac{n^2 - 4n + 1}{2n^2 + n - 3}$."},"indices":["Concentres-toi sur les puissances de $n$ les plus élevées au numérateur et au dénominateur.","N''oublie pas de factoriser par $n^2$ en haut et en bas.","Pense aux limites des fractions du type $\\frac{k}{n^p}$ quand $n$ tend vers l''infini."],"exercice_id":"c88e84bd-1531-47de-a43c-db108b67f33e"}', NULL),
    ('3622cbbf-6064-4f9f-a0ea-153f1313323a'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T15:51:00.704021+00:00'::timestamptz, '4c3f2689-b0e2-4f16-a682-59c94b7ff693'::uuid, 'user', 'La limite c''est 1/2, parce qu''on factorise en haut et en bas par n^2, et ensuite la limite de 1/n ou 1/n^2 c''est 0', NULL);

INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('a2915b0f-fdf1-4b46-b68d-00a4c2768697'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T15:51:04.00222+00:00'::timestamptz, '4c3f2689-b0e2-4f16-a682-59c94b7ff693'::uuid, 'assistant', 'C''est exact, la limite est bien $1/2$ ! Maintenant, montre-moi **en détail** comment tu es arrivé à ce résultat (calculs, factorisations, passage à la limite). C''est essentiel pour vérifier ta compréhension.', NULL),
    ('a5e10a65-cc8b-43d9-8bcd-1f678099c7af'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T15:51:24.338146+00:00'::timestamptz, '4c3f2689-b0e2-4f16-a682-59c94b7ff693'::uuid, 'user', 'ce que je viens d''écrire est correct non?', NULL);

INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('e20912f0-48fa-491d-8142-774f63637d19'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T15:51:32.262141+00:00'::timestamptz, 'c78d5408-d952-417f-84f2-684587b08c92'::uuid, 'assistant', '{"type":"exercice_genere","chapitre":"Suites numériques","solution_complete":"1. Calcul des premiers termes :\n$U_0 = 5$\n$U_1 = \\frac{1}{2}(5) + 3 = 2.5 + 3 = 5.5$\n$U_2 = \\frac{1}{2}(5.5) + 3 = 2.75 + 3 = 5.75$\n$U_3 = \\frac{1}{2}(5.75) + 3 = 2.875 + 3 = 5.875$\n\n2. La suite $(U_n)$ ne semble pas arithmétique car :\n$U_1 - U_0 = 5.5 - 5 = 0.5$\n$U_2 - U_1 = 5.75 - 5.5 = 0.25$\nLa différence n''est pas constante.\n\n3. La suite $(U_n)$ ne semble pas géométrique car :\n$\\frac{U_1}{U_0} = \\frac{5.5}{5} = 1.1$\n$\\frac{U_2}{U_1} = \\frac{5.75}{5.5} \\approx 1.045$\nLe quotient n''est pas constant.\n\n4. Calcul de $V_0$, $V_1$ et $V_2$ :\n$V_0 = U_0 - 6 = 5 - 6 = -1$\n$V_1 = U_1 - 6 = 5.5 - 6 = -0.5$\n$V_2 = U_2 - 6 = 5.75 - 6 = -0.25$\n\n5. Montrons que la suite $(V_n)$ est géométrique :\nOn a $V_n = U_n - 6$, donc $U_n = V_n + 6$.\nOn sait que $U_{n+1} = \\frac{1}{2}U_n + 3$.\nRemplaçons $U_n$ et $U_{n+1}$ :\n$V_{n+1} + 6 = \\frac{1}{2}(V_n + 6) + 3$\n$V_{n+1} + 6 = \\frac{1}{2}V_n + \\frac{1}{2}(6) + 3$\n$V_{n+1} + 6 = \\frac{1}{2}V_n + 3 + 3$\n$V_{n+1} + 6 = \\frac{1}{2}V_n + 6$\n$V_{n+1} = \\frac{1}{2}V_n$\nLa suite $(V_n)$ est donc une suite géométrique de raison $q = \\frac{1}{2}$ et de premier terme $V_0 = -1$.\n\n6. Expression de $V_n$ en fonction de $n$ :\nComme $(V_n)$ est une suite géométrique, $V_n = V_0 \\times q^n$.\n$V_n = -1 \\times (\\frac{1}{2})^n = -(\\frac{1}{2})^n$.\n\n7. Déduction de $U_n$ en fonction de $n$ :\nOn a $V_n = U_n - 6$, donc $U_n = V_n + 6$.\n$U_n = -(\\frac{1}{2})^n + 6$.","difficulte":"moyen","enonce":{"contexte":"Soit la suite $(U_n)$ définie par $U_0 = 5$ et, pour tout entier naturel $n$, $U_{n+1} = \\frac{1}{2}U_n + 3$.","questions":["Calcule les trois premiers termes de la suite : $U_1$, $U_2$ et $U_3$.","La suite $(U_n)$ semble-t-elle arithmétique ? Justifie ta réponse.","La suite $(U_n)$ semble-t-elle géométrique ? Justifie ta réponse.","On considère la suite $(V_n)$ définie pour tout entier naturel $n$ par $V_n = U_n - 6$. Calcule $V_0$, $V_1$ et $V_2$.","Montre que la suite $(V_n)$ est une suite géométrique. Précise sa raison et son premier terme.","Exprime $V_n$ en fonction de $n$.","En déduis l''expression de $U_n$ en fonction de $n$."]},"justification":"Première interaction : exercice d''évaluation de niveau sur les suites, avec un découpage en micro-questions pour évaluer chaque étape de la résolution. Le chapitre est choisi pour être représentatif du programme de lycée.","message_introduction":"C''est notre première session, donc je te propose un exercice découpé en petites étapes pour comprendre où tu en es. 😊","indices":["Pour calculer les termes, utilise la relation $U_{n+1} = \\frac{1}{2}U_n + 3$ en partant de $U_0 = 5$.","Pour savoir si une suite est arithmétique, tu dois vérifier si la différence entre deux termes consécutifs est constante. C''est-à-dire si $U_{n+1} - U_n$ est une constante.","Pour savoir si une suite est géométrique, tu dois vérifier si le quotient entre deux termes consécutifs est constant. C''est-à-dire si $\\frac{U_{n+1}}{U_n}$ est une constante.","Pour montrer que $(V_n)$ est géométrique, exprime $V_{n+1}$ en fonction de $V_n$. N''oublie pas d''utiliser l''expression $U_n = V_n + 6$.","Une fois que tu as $V_n$ en fonction de $n$, tu peux facilement trouver $U_n$ en fonction de $n$ grâce à la relation $V_n = U_n - 6$."],"exercice_id":"329b1c28-7eb3-444d-967c-c6a7d0f483b2"}', NULL),
    ('0c6f676f-bff3-4529-b914-17dd192a5233'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T15:51:53.213242+00:00'::timestamptz, 'c78d5408-d952-417f-84f2-684587b08c92'::uuid, 'user', 'euh pourquoi tu me proposes un nouvel exercice là?', NULL);

INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('10dc4bce-71b6-4696-8d8c-380f9a2d75fb'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T15:51:59.039889+00:00'::timestamptz, 'c78d5408-d952-417f-84f2-684587b08c92'::uuid, 'assistant', '{"solution_complete":"1. Calcul des premiers termes :\n$U_0 = 5$\n$U_1 = \\frac{1}{2}(5) + 3 = 2.5 + 3 = 5.5$\n$U_2 = \\frac{1}{2}(5.5) + 3 = 2.75 + 3 = 5.75$\n$U_3 = \\frac{1}{2}(5.75) + 3 = 2.875 + 3 = 5.875$\n\n2. La suite $(U_n)$ ne semble pas arithmétique car :\n$U_1 - U_0 = 5.5 - 5 = 0.5$\n$U_2 - U_1 = 5.75 - 5.5 = 0.25$\nLa différence n''est pas constante.\n\n3. La suite $(U_n)$ ne semble pas géométrique car :\n$\\frac{U_1}{U_0} = \\frac{5.5}{5} = 1.1$\n$\\frac{U_2}{U_1} = \\frac{5.75}{5.5} \\approx 1.045$\nLe quotient n''est pas constant.\n\n4. Calcul de $V_0$, $V_1$ et $V_2$ :\n$V_0 = U_0 - 6 = 5 - 6 = -1$\n$V_1 = U_1 - 6 = 5.5 - 6 = -0.5$\n$V_2 = U_2 - 6 = 5.75 - 6 = -0.25$\n\n5. Montrons que la suite $(V_n)$ est géométrique :\nOn a $V_n = U_n - 6$, donc $U_n = V_n + 6$.\nOn sait que $U_{n+1} = \\frac{1}{2}U_n + 3$.\nRemplaçons $U_n$ et $U_{n+1}$ :\n$V_{n+1} + 6 = \\frac{1}{2}(V_n + 6) + 3$\n$V_{n+1} + 6 = \\frac{1}{2}V_n + \\frac{1}{2}(6) + 3$\n$V_{n+1} + 6 = \\frac{1}{2}V_n + 3 + 3$\n$V_{n+1} + 6 = \\frac{1}{2}V_n + 6$\n$V_{n+1} = \\frac{1}{2}V_n$\nLa suite $(V_n)$ est donc une suite géométrique de raison $q = \\frac{1}{2}$ et de premier terme $V_0 = -1$.\n\n6. Expression de $V_n$ en fonction de $n$ :\nComme $(V_n)$ est une suite géométrique, $V_n = V_0 \\times q^n$.\n$V_n = -1 \\times (\\frac{1}{2})^n = -(\\frac{1}{2})^n$.\n\n7. Déduction de $U_n$ en fonction de $n$ :\nOn a $V_n = U_n - 6$, donc $U_n = V_n + 6$.\n$U_n = -(\\frac{1}{2})^n + 6$.","difficulte":"moyen","message_introduction":"C''est notre première session, donc je te propose un exercice découpé en petites étapes pour comprendre où tu en es. 😊","type":"exercice_genere","justification":"Première interaction : exercice d''évaluation de niveau sur les suites, avec un découpage en micro-questions pour évaluer chaque étape de la résolution. Le chapitre est choisi pour être représentatif du programme de lycée.","indices":["Pour calculer les termes, utilise la relation $U_{n+1} = \\frac{1}{2}U_n + 3$ en partant de $U_0 = 5$.","Pour savoir si une suite est arithmétique, tu dois vérifier si la différence entre deux termes consécutifs est constante. C''est-à-dire si $U_{n+1} - U_n$ est une constante.","Pour savoir si une suite est géométrique, tu dois vérifier si le quotient entre deux termes consécutifs est constant. C''est-à-dire si $\\frac{U_{n+1}}{U_n}$ est une constante.","Pour montrer que $(V_n)$ est géométrique, exprime $V_{n+1}$ en fonction de $V_n$. N''oublie pas d''utiliser l''expression $U_n = V_n + 6$.","Une fois que tu as $V_n$ en fonction de $n$, tu peux facilement trouver $U_n$ en fonction de $n$ grâce à la relation $V_n = U_n - 6$."],"enonce":{"contexte":"Soit la suite $(U_n)$ définie par $U_0 = 5$ et, pour tout entier naturel $n$, $U_{n+1} = \\frac{1}{2}U_n + 3$.","questions":["Calcule les trois premiers termes de la suite : $U_1$, $U_2$ et $U_3$.","La suite $(U_n)$ semble-t-elle arithmétique ? Justifie ta réponse.","La suite $(U_n)$ semble-t-elle géométrique ? Justifie ta réponse.","On considère la suite $(V_n)$ définie pour tout entier naturel $n$ par $V_n = U_n - 6$. Calcule $V_0$, $V_1$ et $V_2$.","Montre que la suite $(V_n)$ est une suite géométrique. Précise sa raison et son premier terme.","Exprime $V_n$ en fonction de $n$.","En déduis l''expression de $U_n$ en fonction de $n$."]},"chapitre":"Suites numériques","exercice_id":"329b1c28-7eb3-444d-967c-c6a7d0f483b2"}', NULL),
    ('6d68b925-e0ef-4c6e-94bd-de12d40d8927'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T16:38:39.928702+00:00'::timestamptz, '0ec5e8f5-5e03-4cf6-b0d8-5b105b37048b'::uuid, 'user', 'donne moi un exercice sur la fonction exponentielle', NULL);

INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('68589cd4-e47a-4f44-94df-cc701b04af7a'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T16:38:49.197285+00:00'::timestamptz, '91d0858a-c6d7-4c73-88cc-f1ce70f1d2d6'::uuid, 'assistant', '{"indices":["Pour la dérivée, pense à la formule de dérivation d''un produit : $(uv)'' = u''v + uv''$.","Pour le signe de $f''(x)$, souviens-toi que $e^x$ est toujours strictement positif.","Pour la limite en $- \\infty$, tu devras utiliser le fait que $\\lim_{x \\to -\\infty} xe^x = 0$.","N''oublie pas d''indiquer les limites dans le tableau de variations.","L''équation de la tangente en un point d''abscisse $a$ est $y = f''(a)(x-a) + f(a)$."],"chapitre":"Fonction exponentielle","difficulte":"moyen","enonce":{"questions":["Calcule la dérivée $f''(x)$ de la fonction $f$.","Étudie le signe de $f''(x)$ sur $\\mathbb{R}$.","Détermine les limites de $f(x)$ en $+ \\infty$ et en $- \\infty$.","Dresse le tableau de variations complet de la fonction $f$.","Détermine une équation de la tangente à la courbe représentative de $f$ au point d''abscisse $x=0$."],"contexte":"Soit la fonction $f$ définie sur $\\mathbb{R}$ par $f(x) = (2x - 1)e^x$."},"type":"exercice_genere","solution_complete":"1. Calcul de la dérivée :\nOn a $f(x) = (2x - 1)e^x$. C''est un produit de fonctions $u(x) = 2x - 1$ et $v(x) = e^x$.\nAlors $u''(x) = 2$ et $v''(x) = e^x$.\nEn utilisant la formule $(uv)'' = u''v + uv''$, on obtient :\n$f''(x) = 2e^x + (2x - 1)e^x = e^x(2 + 2x - 1) = e^x(2x + 1)$.\n\n2. Étude du signe de $f''(x)$ :\nOn sait que $e^x > 0$ pour tout $x \\in \\mathbb{R}$.\nLe signe de $f''(x)$ est donc le même que le signe de $2x + 1$.\n$2x + 1 > 0 \\iff 2x > -1 \\iff x > -\\frac{1}{2}$.\n$2x + 1 < 0 \\iff x < -\\frac{1}{2}$.\n$2x + 1 = 0 \\iff x = -\\frac{1}{2}$.\nDonc $f''(x) > 0$ pour $x > -\\frac{1}{2}$, $f''(x) < 0$ pour $x < -\\frac{1}{2}$ et $f''(x) = 0$ pour $x = -\\frac{1}{2}$.\n\n3. Détermination des limites :\nEn $+ \\infty$ :\n$\\lim_{x \\to +\\infty} (2x - 1) = +\\infty$.\n$\\lim_{x \\to +\\infty} e^x = +\\infty$.\nDonc, par produit, $\\lim_{x \\to +\\infty} f(x) = +\\infty$.\n\nEn $- \\infty$ :\n$\\lim_{x \\to -\\infty} (2x - 1) = -\\infty$.\n$\\lim_{x \\to -\\infty} e^x = 0$.\nC''est une forme indéterminée. On peut écrire $f(x) = 2xe^x - e^x$.\nOn sait que $\\lim_{x \\to -\\infty} xe^x = 0$.\nDonc $\\lim_{x \\to -\\infty} 2xe^x = 0$.\nEt $\\lim_{x \\to -\\infty} e^x = 0$.\nPar somme, $\\lim_{x \\to -\\infty} f(x) = 0 - 0 = 0$.\n\n4. Tableau de variations :\n$\\begin{array}{|c|ccccccc|}\n\\hline\nx & -\\infty & & -\\frac{1}{2} & & +\\infty \\\\\n\\hline\n2x+1 & & - & 0 & + & \\\\\n\\hline\ne^x & & + & & + & \\\\\n\\hline\nf''(x) & & - & 0 & + & \\\\\n\\hline\nf(x) & 0 & \\searrow & -2e^{-\\frac{1}{2}} & \\nearrow & +\\infty \\\\\n\\hline\n\\end{array}$\nPour $x = -\\frac{1}{2}$, $f(-\\frac{1}{2}) = (2(-\\frac{1}{2}) - 1)e^{-\\frac{1}{2}} = (-1 - 1)e^{-\\frac{1}{2}} = -2e^{-\\frac{1}{2}}$.\n\n5. Équation de la tangente au point d''abscisse $x=0$ :\nOn utilise la formule $y = f''(0)(x-0) + f(0)$.\nOn a $f(0) = (2(0) - 1)e^0 = -1 \\times 1 = -1$.\nEt $f''(0) = e^0(2(0) + 1) = 1 \\times 1 = 1$.\nDonc l''équation de la tangente est $y = 1(x - 0) + (-1)$, soit $y = x - 1$.","justification":"Première interaction sur ce chapitre, exercice de difficulté moyenne pour évaluer les compétences sur la dérivation, les limites et le tableau de variations de fonctions exponentielles. Inclut une question sur la tangente pour un aspect plus complet.","message_introduction":"Bonjour ! Puisque tu veux travailler la fonction exponentielle, je te propose un exercice pour revoir les bases et les propriétés importantes. Prends ton temps pour chaque question !","exercice_id":"c672d7b9-8f89-4af5-8667-e199827a1025"}', NULL),
    ('d80cd642-a1cc-4f9d-be4b-b4a11985e19b'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T16:41:19.025152+00:00'::timestamptz, '91d0858a-c6d7-4c73-88cc-f1ce70f1d2d6'::uuid, 'user', '1.dérivée de la fonction: exp(x)* (2x+1)
2. f'' est négative pour x<= 1/2, et positive pour x>= 1/2
3. f tend vers moins l''infini en moins l''infini et +infini en +infini
4. f est croissante sur [-1/2, +infini] et décroissante sur [-infini, 1/2]', NULL);

