INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('02ff244e-72b2-48c9-b24c-2d4ba6ed5837'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-25T16:44:34.711427+00:00'::timestamptz, '91d0858a-c6d7-4c73-88cc-f1ce70f1d2d6'::uuid, 'assistant', '{"type":"math_graph","expression":"x","xMin":-10,"xMax":10,"title":"f(x) = x","message_introduction":"Voici le graphique de la fonction ! 📊"}', NULL),
