INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('8bca5591-9791-4672-900d-0211d588fa0d'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-29T19:40:03.275544+00:00'::timestamptz, '74f65a77-7945-4721-b70c-3321bbf858f8'::uuid, 'user', 'Mais je t’ai donné l’énoncé en photo…', NULL),
    ('eecd3b1a-ca5d-4afa-8fcd-8facc0eaaf95'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-10-29T19:40:07.402819+00:00'::timestamptz, '74f65a77-7945-4721-b70c-3321bbf858f8'::uuid, 'assistant', 'Ah oui, tu as raison ! Je suis désolée, j''ai eu un petit trou de mémoire. Je n''ai pas accès aux photos que tu m''as envoyées précédemment. En tant qu''IA, je ne peux pas "voir" les images, je ne peux traiter que le texte.

