INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('c631f644-f675-4d2e-b36b-00dbc7b59a87'::uuid, '9ad37b01-a2c0-4b06-b32b-b5a0b29dba21'::uuid, '2025-10-30T11:00:25.476782+00:00'::timestamptz, 'c01ce87f-c835-4067-80bd-1e4973356a94'::uuid, 'user', 'regarde la photo', NULL),
    ('e8b4df45-e06f-4806-a3e4-43f9ef2f1236'::uuid, '9ad37b01-a2c0-4b06-b32b-b5a0b29dba21'::uuid, '2025-10-30T11:00:28.701998+00:00'::timestamptz, 'c01ce87f-c835-4067-80bd-1e4973356a94'::uuid, 'assistant', 'D''accord Gabriel, je comprends ! Tu me demandes de regarder la pho\to que tu as jointe pour la question 3.

Je vais analyser la pho\to que tu m''as envoyée.

