INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('b2487f05-fa81-4c09-8eb1-70b9452e67a5'::uuid, '9ad37b01-a2c0-4b06-b32b-b5a0b29dba21'::uuid, '2025-10-30T11:41:32.553884+00:00'::timestamptz, '870d51a6-8c1a-4e4a-b287-dfd88046c7b6'::uuid, 'user', 'Non c’est le 2. De l’exercice 2', 'https://yswfjckmxmosawmsuljd.supabase.co/storage/v1/object/public/student-responses/9ad37b01-a2c0-4b06-b32b-b5a0b29dba21/1761824489561.jpg'),
    ('2ae5eb9b-a8ee-441a-a10b-4d95c22f3dec'::uuid, '9ad37b01-a2c0-4b06-b32b-b5a0b29dba21'::uuid, '2025-10-30T11:41:40.43808+00:00'::timestamptz, '870d51a6-8c1a-4e4a-b287-dfd88046c7b6'::uuid, 'assistant', 'Ah, d''accord Gabriel ! Je comprends mieux. Tu fais référence à la question 2 de l''Exercice 2, qui est une suite de la première question.

