INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('95ff74fd-068f-4414-86b5-b48cf33f8b0c'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-11-01T17:54:07.301449+00:00'::timestamptz, '34584101-f01c-4b87-88c5-570cdff1ec38'::uuid, 'assistant', 'Super ! Des exemples d''exercices, c''est le meilleur moyen de bien comprendre et de s''entraîner.

Voici un premier exercice pour appliquer le théorème de Thalès :

---

**Exercice 1 :**

Soit un triangle ABC. On place un point M sur le segment [AB] et un point N sur le segment [AC] tels que la droite (MN) soit parallèle à la droite (BC).

On donne les mesures suivantes :
*   $AM = 3$ cm
*   $AB = 9$ cm
*   $AN = 2$ cm

Calcule la longueur $AC$.

---

Prends ton temps pour le résoudre. N''hésite pas si tu as des questions ou si tu veux que je te donne un indice !', NULL),
    ('aab04918-4672-46ed-a6d0-c8f313f4c8a0'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-11-02T09:24:34.069079+00:00'::timestamptz, '3ee80a7b-21c2-4b4f-9007-fce0cca35125'::uuid, 'assistant', '{"solution_complete":"1. Pour qu''une situation puisse être modélisée par une loi binomiale, trois conditions doivent être remplies :\n   - **Répétition d''épreuves identiques et indépendantes :** Ici, on prélève $20$ puces. Les prélèvements sont effectués ''avec remise'', ce qui garantit l''indépendance des épreuves et que la probabilité de défectuosité reste constante pour chaque puce.\n   - **Deux issues possibles par épreuve :** Pour chaque puce prélevée, il y a deux issues possibles : ''la puce est défectueuse'' (succès) ou ''la puce n''est pas défectueuse'' (échec).\n   - **Probabilité de succès constante :** La probabilité qu''une puce soit défectueuse est de $5\\%$, soit $p = 0,05$. Cette probabilité est constante pour chaque prélèvement.\n\n   Les trois conditions sont remplies, donc la situation peut être modélisée par une loi binomiale. Ses paramètres sont :\n   - $n = 20$ (nombre de répétitions de l''expérience)\n   - $p = 0,05$ (probabilité de succès, c''est-à-dire la probabilité qu''une puce soit défectueuse)\n\n2. Les trois critères essentiels pour qu''une expérience aléatoire suive une loi binomiale sont :\n   - L''expérience est une répétition de $n$ épreuves identiques et indépendantes.\n   - Chaque épreuve n''a que deux issues possibles : un ''succès'' ou un ''échec''.\n   - La probabilité de succès $p$ est la même à chaque épreuve.","justification":"L''élève a une lacune identifiée sur la justification de la loi binomiale. L''exercice est ciblé pour qu''il puisse maîtriser cette notion en se focalisant sur les conditions d''application. La difficulté est difficile car il doit justifier et expliciter les trois conditions.","type":"exercice_genere","indices":["Réfléchis aux conditions de répétition des épreuves.","Pense à la nature des issues de chaque épreuve.","La probabilité de succès doit être constante.","Les tirages sont effectués ''avec remise''."],"enonce":{"questions":["Justifie si la situation peut être modélisée par une loi binomiale. Si oui, précise ses paramètres $n$ et $p$.","Quels sont les trois critères essentiels pour qu''une expérience aléatoire suive une loi binomiale ?"],"contexte":"Un fabricant de composants électroniques produit des puces. On sait que $5\\%$ des puces produites sont défectueuses. Pour un contrôle qualité, on prélève au hasard et avec remise un échantillon de $20$ puces."},"difficulte":"difficile","message_introduction":"J''ai remarqué que tu as fait plusieurs erreurs récurrentes sur la Justification de la loi binomiale - Conditions d''application. C''est important de bien consolider cette notion avant d''aller plus loin. Je vais te proposer un exercice ciblé sur la Justification de la loi binomiale - Conditions d''application pour que tu puisses bien la maîtriser. Ça te va ?","chapitre":"Probabilités","exercice_id":"b6786bbd-c581-4850-9b17-9c2efd25340d"}', NULL);

INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('139861e8-d460-4b4d-b34c-ecd54aa8eca4'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-11-02T09:25:08.271213+00:00'::timestamptz, '910b91f6-7686-4988-9000-0764b2ca16af'::uuid, 'assistant', '{"solution_complete":"De l''équation (1), $z = x + 2y - 5$.\nSubstituons $z$ dans l''équation (2) :\n$2x - y + 3(x + 2y - 5) = 0$\n$2x - y + 3x + 6y - 15 = 0$\n$5x + 5y = 15$\n$x + y = 3$ (Équation 4)\n\nSubstituons $z$ dans l''équation (3) :\n$3x + y + 2(x + 2y - 5) = 3$\n$3x + y + 2x + 4y - 10 = 3$\n$5x + 5y = 13$ (Équation 5)\n\nNous avons maintenant un système 2x2 avec les équations (4) et (5) :\n$\\begin{cases} x + y = 3 \\\\ 5x + 5y = 13 \\end{cases}$\n\nDe l''équation (4), $y = 3 - x$. Substituons dans l''équation (5) :\n$5x + 5(3 - x) = 13$\n$5x + 15 - 5x = 13$\n$15 = 13$\n\nCeci est une contradiction. Le système n''a pas de solution. Il est incompatible.","type":"exercice_genere","message_introduction":"Tu as déjà travaillé sur les systèmes d''équations, et puisque tu progresses bien, je te propose un exercice complet sur la résolution de systèmes 3x3. C''est un bon défi pour voir si tu maîtrises bien la méthode !","chapitre":"Systèmes d''équations linéaires","difficulte":"difficile","justification":"L''élève a un taux de réussite de 80% et n''a pas de lacune sur ce chapitre. Un exercice de difficulté difficile est approprié. La résolution d''un système 3x3 demande de la rigueur et de la méthode. Le fait que le système n''ait pas de solution ajoute à la difficulté et oblige l''élève à bien vérifier ses calculs et son raisonnement.","indices":["Tu peux commencer par éliminer une variable dans deux des équations pour obtenir un système 2x2. Par exemple, essaie d''éliminer $z$ des deux premières équations.","Une fois le système 2x2 obtenu, résous-le pour trouver les valeurs de deux variables.","Substitue les valeurs trouvées dans l''une des équations originales pour trouver la troisième variable.","N''oublie pas de vérifier ta solution en la remplaçant dans les trois équations de départ."],"enonce":{"questions":["$$\\begin{cases} x + 2y - z = 5 \\\\ 2x - y + 3z = 0 \\\\ 3x + y + 2z = 3 \\end{cases}$$"],"contexte":"Résous le système d''équations linéaires suivant :"},"exercice_id":"dbfb7851-a77f-4fe7-9bd5-ca4ec05977ff"}', NULL),
    ('ee417324-03f0-4b7a-8cbb-b46ab1832bf5'::uuid, '1e6d88c3-5ca8-4091-afba-05b47b40da66'::uuid, '2025-11-02T09:28:58.275756+00:00'::timestamptz, '62c4407a-2c39-4368-a4a0-b4300cac9704'::uuid, 'user', '📸 Réponse manuscrite', 'https://yswfjckmxmosawmsuljd.supabase.co/storage/v1/object/public/student-responses/1e6d88c3-5ca8-4091-afba-05b47b40da66/1762075730331.png');

