    ('3e15c7e3-a985-44cf-aad4-943345ff02fc'::uuid, '286418fb-4193-4498-a2d9-521618358b37'::uuid, '2025-11-02T10:24:03.753661+00:00'::timestamptz, 'f903eabb-703a-46aa-bbcd-569a04e851ba'::uuid, 'user', 'AA′
