    ('901068ed-b027-4bc6-b177-8ab6dbb19af1'::uuid, '286418fb-4193-4498-a2d9-521618358b37'::uuid, '2025-11-02T10:24:34.692224+00:00'::timestamptz, 'f903eabb-703a-46aa-bbcd-569a04e851ba'::uuid, 'user', 'car Par définition de 
