    ('eb982270-c435-402f-8952-30d6e90fe286'::uuid, '286418fb-4193-4498-a2d9-521618358b37'::uuid, '2025-11-02T11:15:34.686123+00:00'::timestamptz, '65b007b6-5e1c-4540-a60e-162744c2b9e0'::uuid, 'user', 'ef = − 
