INSERT INTO public.chat_history (id, user_id, created_at, chat_id, role, content, image_url) VALUES
    ('ff51984b-ee17-4043-a89f-3c4213812008'::uuid, '5c6c30a8-6754-4d31-82ff-f198bb5c51ef'::uuid, '2025-11-03T14:05:56.113659+00:00'::timestamptz, '124f8f9e-0262-4793-bccb-9e6fc89e41af'::uuid, 'assistant', 'Content de te revoir Maxence ! C''est une excellente idée de vouloir résoudre cette intégrale.

Pour commencer, quelle serait ta première étape pour calculer $\\int_0^1\\frac{1}{x^2-2x+5}\\differentialD x$ ?

Pense à la forme du dénominateur, $x^2 - 2x + 5$. Est-ce que ça t''évoque quelque chose ?', NULL),
    ('3875b11a-5ab9-4a42-b93b-bf7421ee8253'::uuid, '5c6c30a8-6754-4d31-82ff-f198bb5c51ef'::uuid, '2025-11-03T14:05:56.798242+00:00'::timestamptz, '62dca717-3786-4310-995a-87e0ed00f172'::uuid, 'assistant', 'Content de te revoir aussi Maxence ! C''est une excellente idée de vouloir résoudre cette intégrale. C''est un bon classique pour s''exercer sur les fonctions rationnelles.

