    ('eefd3728-9675-4979-98e5-e12bbc70b871'::uuid, 'a94f2136-cae9-41b0-b97e-d007f737d093'::uuid, '2025-11-16T19:15:05.389716+00:00'::timestamptz, 'eca74192-25a4-44ae-9166-ccaa72cd5a99'::uuid, 'user', '
