    ('b95e0344-2a1a-4bb5-9119-cc128678ddea'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '2025-11-17T09:17:20.886315+00:00'::timestamptz, 'b549dde5-fee7-4c30-b071-3b0841058dfd'::uuid, 'user', 'ça s''est mal affiché tu peux réécrire stp', NULL),
